import React, { useState, useEffect } from 'react';
import { User, Mail, Shield, Key, Camera, LogOut } from 'lucide-react';
import { motion } from 'framer-motion';
import { setAuthToken } from '../services/api';
import { useNavigate } from 'react-router-dom';

export default function Profile() {
    const navigate = useNavigate();
    const [isEditing, setIsEditing] = useState(false);

    // Password Modal State
    const [isPasswordModalOpen, setIsPasswordModalOpen] = useState(false);
    const [passwords, setPasswords] = useState({ current: '', new: '', confirm: '' });
    const [passwordError, setPasswordError] = useState('');
    const [passwordSuccess, setPasswordSuccess] = useState('');

    // Using placeholder data since we don't have a GET /me endpoint yet
    const [profile, setProfile] = useState({
        name: 'VidyaMitra User',
        email: 'user@example.com',
        role: 'Job Seeker',
        phone: '+1 (555) 000-0000',
        location: 'San Francisco, CA'
    });

    // Load profile from local storage on component mount
    useEffect(() => {
        const savedProfile = localStorage.getItem('vidyamitra_user_profile');
        if (savedProfile) {
            try {
                setProfile(JSON.parse(savedProfile));
            } catch (e) {
                console.error("Could not parse saved profile data", e);
            }
        }
    }, []);

    const handleSaveProfile = () => {
        if (isEditing) {
            // About to toggle off, save to local storage
            localStorage.setItem('vidyamitra_user_profile', JSON.stringify(profile));
        }
        setIsEditing(!isEditing);
    };

    const handleLogout = () => {
        setAuthToken(null);
        navigate('/');
    };

    const handleChangePassword = (e) => {
        e.preventDefault();
        setPasswordError('');
        setPasswordSuccess('');

        if (passwords.new !== passwords.confirm) {
            setPasswordError("New passwords don't match");
            return;
        }
        if (passwords.new.length < 6) {
            setPasswordError("Password must be at least 6 characters");
            return;
        }

        // Mock successful password change
        setPasswordSuccess("Password updated successfully!");
        setTimeout(() => {
            setIsPasswordModalOpen(false);
            setPasswords({ current: '', new: '', confirm: '' });
            setPasswordSuccess('');
        }, 1500);
    };

    return (
        <div className="max-w-4xl space-y-8">
            {/* Header Profile Card */}
            <div className="glass-panel p-8 rounded-3xl relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-32 bg-gradient-to-r from-primary-500 to-indigo-600"></div>

                <div className="relative pt-16 sm:pt-20 flex flex-col sm:flex-row items-center sm:items-end gap-6">
                    <div className="relative group">
                        <button
                            className="w-32 h-32 rounded-full border-4 border-white bg-slate-100 shadow-xl overflow-hidden flex items-center justify-center bg-gradient-to-tr from-primary-100 to-indigo-100 hover:scale-105 transition-transform"
                            onClick={() => alert('Profile picture upload clicked')}
                        >
                            <span className="text-5xl font-black text-indigo-400">U</span>
                        </button>
                        <button
                            className="absolute bottom-2 right-2 p-2 bg-white rounded-full shadow-md text-slate-600 hover:text-primary-600 transition opacity-0 group-hover:opacity-100 pointer-events-none"
                        >
                            <Camera className="w-4 h-4" />
                        </button>
                    </div>

                    <div className="flex-1 text-center sm:text-left">
                        <h2 className="text-3xl font-extrabold text-slate-900">{profile.name}</h2>
                        <p className="text-slate-500 font-medium">{profile.role} ΓÇó {profile.location}</p>
                    </div>

                    <div className="flex gap-3">
                        <button
                            onClick={handleSaveProfile}
                            className="px-6 py-2.5 bg-white border border-slate-200 text-slate-700 rounded-xl font-semibold shadow-sm hover:bg-slate-50 transition"
                        >
                            {isEditing ? 'Save Changes' : 'Edit Profile'}
                        </button>
                    </div>
                </div>
            </div>

            {/* Profile Details Grid */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">

                {/* Personal Information */}
                <div className="md:col-span-2 glass-panel p-8 rounded-3xl space-y-6">
                    <h3 className="text-xl font-bold text-slate-800 border-b border-slate-100 pb-4">Personal Information</h3>

                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                        <div className="space-y-1">
                            <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Full Name</label>
                            {isEditing ? (
                                <input type="text" className="w-full p-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-primary-500 transition" value={profile.name} onChange={e => setProfile({ ...profile, name: e.target.value })} />
                            ) : (
                                <p className="font-semibold text-slate-800">{profile.name}</p>
                            )}
                        </div>
                        <div className="space-y-1">
                            <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Email Address</label>
                            {isEditing ? (
                                <input type="email" className="w-full p-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-primary-500 transition" value={profile.email} onChange={e => setProfile({ ...profile, email: e.target.value })} />
                            ) : (
                                <p className="font-semibold text-slate-800 flex items-center gap-2"><Mail className="w-4 h-4 text-slate-400" /> {profile.email}</p>
                            )}
                        </div>
                        <div className="space-y-1">
                            <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Phone</label>
                            {isEditing ? (
                                <input type="tel" className="w-full p-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-primary-500 transition" value={profile.phone} onChange={e => setProfile({ ...profile, phone: e.target.value })} />
                            ) : (
                                <p className="font-semibold text-slate-800">{profile.phone}</p>
                            )}
                        </div>
                        <div className="space-y-1">
                            <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Location</label>
                            {isEditing ? (
                                <input type="text" className="w-full p-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-primary-500 transition" value={profile.location} onChange={e => setProfile({ ...profile, location: e.target.value })} />
                            ) : (
                                <p className="font-semibold text-slate-800">{profile.location}</p>
                            )}
                        </div>
                    </div>
                </div>

                {/* Security Settings */}
                <div className="glass-panel p-8 rounded-3xl space-y-6">
                    <h3 className="text-xl font-bold text-slate-800 border-b border-slate-100 pb-4">Security</h3>

                    <button
                        onClick={() => setIsPasswordModalOpen(true)}
                        className="w-full flex items-center justify-between p-4 rounded-xl border border-slate-200 hover:border-primary-300 hover:shadow-md transition group bg-white cursor-pointer"
                    >
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-slate-50 rounded-lg group-hover:bg-primary-50 text-slate-600 group-hover:text-primary-600 transition">
                                <Key className="w-5 h-5" />
                            </div>
                            <div className="text-left">
                                <p className="font-bold text-slate-800 text-sm">Change Password</p>
                                <p className="text-xs text-slate-500">Update your credentials</p>
                            </div>
                        </div>
                    </button>

                    {/* Two-Factor Auth Removed as Per Request */}

                    <div className="pt-6 mt-6 border-t border-slate-100">
                        <button onClick={handleLogout} className="w-full flex items-center justify-center gap-2 px-4 py-3 bg-red-50 text-red-600 rounded-xl font-bold hover:bg-red-100 hover:shadow-sm transition">
                            <LogOut className="w-5 h-5" /> Sign Out from Account
                        </button>
                    </div>
                </div>

            </div>

            {/* Password Change Modal Overlay */}
            {isPasswordModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/50 backdrop-blur-sm p-4">
                    <motion.div
                        initial={{ opacity: 0, scale: 0.95 }}
                        animate={{ opacity: 1, scale: 1 }}
                        className="bg-white rounded-3xl shadow-2xl max-w-md w-full p-8 border border-slate-100"
                    >
                        <h3 className="text-2xl font-bold text-slate-800 mb-6 flex items-center gap-2">
                            <Key className="w-6 h-6 text-primary-500" />
                            Change Password
                        </h3>

                        {passwordError && <p className="text-red-500 text-sm mb-4 p-3 bg-red-50 rounded-lg border border-red-100">{passwordError}</p>}
                        {passwordSuccess && <p className="text-green-600 text-sm mb-4 p-3 bg-green-50 rounded-lg border border-green-100 font-medium">{passwordSuccess}</p>}

                        <form onSubmit={handleChangePassword} className="space-y-4">
                            <div>
                                <label className="block text-sm font-semibold text-slate-700 mb-1">Current Password</label>
                                <input
                                    type="password" required
                                    className="w-full p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-primary-500 bg-slate-50 transition"
                                    value={passwords.current}
                                    onChange={e => setPasswords({ ...passwords, current: e.target.value })}
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-semibold text-slate-700 mb-1">New Password</label>
                                <input
                                    type="password" required
                                    className="w-full p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-primary-500 bg-slate-50 transition"
                                    value={passwords.new}
                                    onChange={e => setPasswords({ ...passwords, new: e.target.value })}
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-semibold text-slate-700 mb-1">Confirm New Password</label>
                                <input
                                    type="password" required
                                    className="w-full p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-primary-500 bg-slate-50 transition"
                                    value={passwords.confirm}
                                    onChange={e => setPasswords({ ...passwords, confirm: e.target.value })}
                                />
                            </div>

                            <div className="flex gap-3 pt-4">
                                <button
                                    type="button"
                                    onClick={() => {
                                        setIsPasswordModalOpen(false);
                                        setPasswords({ current: '', new: '', confirm: '' });
                                        setPasswordError('');
                                    }}
                                    className="flex-1 px-4 py-3 bg-white border border-slate-200 text-slate-600 rounded-xl font-semibold hover:bg-slate-50 transition"
                                >
                                    Cancel
                                </button>
                                <button
                                    type="submit"
                                    className="flex-1 px-4 py-3 bg-primary-600 text-white rounded-xl font-semibold shadow-md hover:bg-primary-700 transition"
                                >
                                    Update Password
                                </button>
                            </div>
                        </form>
                    </motion.div>
                </div>
            )}
        </div>
    );
}

import React, { useState } from 'react';
import { BookOpen, CheckCircle, HelpCircle, Loader2 } from 'lucide-react';
import { api } from '../services/api';
import { motion } from 'framer-motion';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';

export default function Quiz() {
    const [domain, setDomain] = useState('');
    const [loading, setLoading] = useState(false);
    const [quizData, setQuizData] = useState(null);
    const [error, setError] = useState('');

    const [currentQuestionIdx, setCurrentQuestionIdx] = useState(0);
    const [answers, setAnswers] = useState({});
    const [showResults, setShowResults] = useState(false);

    const handleGenerate = async (e) => {
        e.preventDefault();
        if (!domain.trim()) return;

        setLoading(true);
        setError('');
        setQuizData(null);
        setShowResults(false);
        setAnswers({});
        setCurrentQuestionIdx(0);

        try {
            const res = await api.post('/interactive/quiz/generate', {
                domain: domain,
                difficulty: "intermediate",
                num_questions: 5
            });
            setQuizData(res.data);
        } catch (err) {
            setError('Failed to generate quiz.');
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    const handleAnswer = (optionIdx) => {
        setAnswers({ ...answers, [currentQuestionIdx]: optionIdx });
    };

    const calculateScore = () => {
        let score = 0;
        quizData.questions.forEach((q, i) => {
            if (answers[i] === q.correct_option_index) {
                score += 1;
            }
        });
        return score;
    };

    return (
        <div className="space-y-6">
            {!quizData && (
                <div className="glass-panel p-6 rounded-2xl">
                    <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2 mb-4">
                        <BookOpen className="w-5 h-5 text-indigo-500" />
                        Adaptive Training Quizzes
                    </h2>

                    <form onSubmit={handleGenerate} className="space-y-5">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2">Topic or Technology</label>
                            <input
                                type="text"
                                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition bg-white/50"
                                placeholder="e.g. React Hooks, System Design, Data Structures"
                                value={domain}
                                onChange={(e) => setDomain(e.target.value)}
                                required
                            />
                        </div>

                        <button
                            type="submit"
                            disabled={loading || !domain}
                            className="px-6 py-3 bg-gradient-to-r from-indigo-500 to-primary-600 text-white rounded-xl font-semibold shadow-md hover:shadow-lg transition disabled:opacity-70 flex items-center gap-2"
                        >
                            {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : 'Start Quiz'}
                        </button>
                    </form>
                    {error && <p className="mt-4 text-red-500 text-sm">{error}</p>}
                </div>
            )}

            {quizData && !showResults && (
                <motion.div
                    initial={{ opacity: 0, scale: 0.98 }}
                    animate={{ opacity: 1, scale: 1 }}
                    className="glass-panel p-8 rounded-2xl max-w-2xl mx-auto"
                >
                    <div className="flex justify-between items-center mb-6">
                        <span className="text-sm font-bold text-indigo-500 bg-indigo-50 px-3 py-1 rounded-full uppercase tracking-wider">{quizData.domain}</span>
                        <span className="text-slate-500 font-medium text-sm">Question {currentQuestionIdx + 1} of {quizData.questions.length}</span>
                    </div>

                    <h3 className="text-2xl font-bold text-slate-800 mb-8 leading-snug">
                        {quizData.questions[currentQuestionIdx].question_text}
                    </h3>

                    <div className="space-y-3 mb-8">
                        {quizData.questions[currentQuestionIdx].options.map((option, idx) => (
                            <button
                                key={idx}
                                onClick={() => handleAnswer(idx)}
                                className={`w-full text-left p-4 rounded-xl border-2 transition font-medium ${answers[currentQuestionIdx] === idx
                                    ? 'border-indigo-500 bg-indigo-50/50 text-indigo-900 shadow-sm transform scale-[1.01]'
                                    : 'border-slate-200 bg-white hover:border-indigo-300 text-slate-700 hover:bg-slate-50'
                                    }`}
                            >
                                <span className="inline-block w-6 h-6 rounded bg-white text-center shadow-sm border border-slate-200 text-slate-500 mr-3 text-sm leading-6">
                                    {String.fromCharCode(65 + idx)}
                                </span>
                                {option}
                            </button>
                        ))}
                    </div>

                    <div className="flex justify-between items-center pt-6 border-t border-slate-100">
                        <button
                            onClick={() => setCurrentQuestionIdx(Math.max(0, currentQuestionIdx - 1))}
                            disabled={currentQuestionIdx === 0}
                            className="text-slate-500 font-medium hover:text-slate-800 transition disabled:opacity-30 disabled:cursor-not-allowed"
                        >
                            Previous
                        </button>

                        {currentQuestionIdx < quizData.questions.length - 1 ? (
                            <button
                                onClick={() => setCurrentQuestionIdx(currentQuestionIdx + 1)}
                                disabled={answers[currentQuestionIdx] === undefined}
                                className="px-6 py-2.5 bg-slate-900 text-white rounded-lg font-medium shadow-md hover:bg-slate-800 transition disabled:opacity-50"
                            >
                                Next Question
                            </button>
                        ) : (
                            <button
                                onClick={async () => {
                                    setShowResults(true);
                                    try {
                                        await api.post('/progress/log', {
                                            module_name: "Last Quiz Score",
                                            score: calculateScore()
                                        });
                                    } catch (err) {
                                        console.error("Failed to log quiz progress", err);
                                    }
                                }}
                                disabled={answers[currentQuestionIdx] === undefined}
                                className="px-6 py-2.5 bg-green-500 text-white rounded-lg font-medium shadow-md hover:bg-green-600 transition disabled:opacity-50 flex items-center gap-2"
                            >
                                <CheckCircle className="w-5 h-5" /> Submit Quiz
                            </button>
                        )}
                    </div>
                </motion.div>
            )}

            {showResults && (
                <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="glass-panel p-8 rounded-2xl max-w-2xl mx-auto shadow-xl border-t-8 border-t-indigo-500"
                >
                    <div className="text-center mb-8">
                        <div className="inline-flex items-center justify-center w-20 h-20 rounded-full bg-indigo-100 text-indigo-600 mb-4 shadow-inner">
                            <span className="text-3xl font-black">{calculateScore()}</span>
                            <span className="text-xl">/{quizData.questions.length}</span>
                        </div>
                        <h2 className="text-2xl font-black text-slate-800 mb-2">Quiz Complete!</h2>
                        <p className="text-slate-500">You've finished the assessment for {quizData.domain}.</p>
                    </div>

                    {/* Results Pie Chart */}
                    <div className="h-64 mb-8 w-full max-w-sm mx-auto">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie
                                    data={[
                                        { name: 'Correct', value: calculateScore() },
                                        { name: 'Incorrect', value: quizData.questions.length - calculateScore() }
                                    ]}
                                    cx="50%"
                                    cy="50%"
                                    innerRadius={60}
                                    outerRadius={80}
                                    paddingAngle={5}
                                    dataKey="value"
                                >
                                    <Cell key="cell-0" fill="#22c55e" />
                                    <Cell key="cell-1" fill="#ef4444" />
                                </Pie>
                                <Tooltip
                                    contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                                    itemStyle={{ fontWeight: 'bold' }}
                                />
                                <Legend verticalAlign="bottom" height={36} iconType="circle" />
                            </PieChart>
                        </ResponsiveContainer>
                    </div>

                    <div className="space-y-6">
                        {quizData.questions.map((q, i) => (
                            <div key={i} className="p-5 rounded-xl border border-slate-100 bg-white shadow-sm">
                                <p className="font-bold text-slate-800 mb-3">{i + 1}. {q.question_text}</p>

                                <div className="text-sm space-y-2">
                                    <p className={`p-3 rounded-lg flex items-center gap-2 font-medium ${answers[i] === q.correct_option_index ? 'bg-green-50 text-green-700 border border-green-200' : 'bg-red-50 text-red-700 border border-red-200'}`}>
                                        {answers[i] === q.correct_option_index ? <CheckCircle className="w-4 h-4" /> : <HelpCircle className="w-4 h-4" />}
                                        Your Answer: {q.options[answers[i]] || "Skipped"}
                                    </p>

                                    {answers[i] !== q.correct_option_index && (
                                        <p className="p-3 bg-indigo-50 text-indigo-700 rounded-lg border border-indigo-100 font-medium">
                                            Correct Answer: {q.options[q.correct_option_index]}
                                        </p>
                                    )}

                                    <p className="text-slate-500 mt-2 px-1 text-sm"><span className="font-bold text-slate-700">Explanation:</span> {q.explanation}</p>
                                </div>
                            </div>
                        ))}
                    </div>

                    <button
                        onClick={() => { setQuizData(null); setDomain(''); }}
                        className="w-full mt-8 px-6 py-3 bg-slate-900 text-white rounded-xl font-semibold shadow-md hover:bg-slate-800 transition"
                    >
                        Take Another Quiz
                    </button>
                </motion.div>
            )}
        </div>
    );
}

import React, { useState } from 'react';
import { Upload, FileText, CheckCircle, AlertCircle, Loader2 } from 'lucide-react';
import { api } from '../services/api';
import { motion } from 'framer-motion';
import { Radar, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, ResponsiveContainer, Tooltip, Legend } from 'recharts';

export default function ResumeAnalyzer() {
    const [resumeText, setResumeText] = useState('');
    const [file, setFile] = useState(null);
    const [loading, setLoading] = useState(false);
    const [analysis, setAnalysis] = useState(null);
    const [error, setError] = useState('');

    const handleAnalyze = async (e) => {
        e.preventDefault();
        if (!resumeText.trim() && !file) return;

        setLoading(true);
        setError('');
        setAnalysis(null);

        try {
            let res;
            if (file) {
                const formData = new FormData();
                formData.append('file', file);
                res = await api.post('/resume/analyze-file', formData, {
                    headers: { 'Content-Type': 'multipart/form-data' }
                });
            } else {
                res = await api.post('/resume/analyze', { resume_text: resumeText });
            }
            setAnalysis(res.data);

            // Log the progress to the backend seamlessly
            try {
                await api.post('/progress/log', {
                    module_name: "Resume Score",
                    score: res.data.score
                });
            } catch (progressErr) {
                console.error("Failed to log progress", progressErr);
            }

        } catch (err) {
            setError('Failed to analyze resume. Please try again.');
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="space-y-6">
            <div className="glass-panel p-6 rounded-2xl">
                <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2 mb-4">
                    <Upload className="w-5 h-5 text-primary-500" />
                    Analyze Your Resume
                </h2>

                <form onSubmit={handleAnalyze} className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-2">Upload Resume (PDF or Image)</label>
                        <div className="flex items-center justify-center w-full mb-4">
                            <label htmlFor="dropzone-file" className="flex flex-col items-center justify-center w-full h-32 border-2 border-slate-300 border-dashed rounded-xl cursor-pointer bg-slate-50 hover:bg-slate-100 transition">
                                <div className="flex flex-col items-center justify-center pt-5 pb-6">
                                    <Upload className="w-8 h-8 mb-3 text-slate-400" />
                                    <p className="mb-2 text-sm text-slate-500"><span className="font-semibold">Click to upload</span> or drag and drop</p>
                                    <p className="text-xs text-slate-500">{file ? file.name : "PDF, PNG, JPG (MAX. 5MB)"}</p>
                                </div>
                                <input id="dropzone-file" type="file" className="hidden" accept=".pdf,.png,.jpg,.jpeg" onChange={(e) => { setFile(e.target.files[0]); setResumeText(''); }} />
                            </label>
                        </div>
                    </div>

                    <div className="flex items-center gap-4 py-2">
                        <hr className="flex-1 border-slate-200" />
                        <span className="text-slate-400 text-sm font-medium">OR</span>
                        <hr className="flex-1 border-slate-200" />
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-2">Paste Resume Text</label>
                        <textarea
                            rows="6"
                            className="w-full p-4 rounded-xl border border-slate-200 focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none transition bg-white/50"
                            placeholder="Paste the content of your resume here to get AI-powered insights..."
                            value={resumeText}
                            onChange={(e) => { setResumeText(e.target.value); setFile(null); }}
                            disabled={!!file}
                        ></textarea>
                    </div>

                    <button
                        type="submit"
                        disabled={loading || (!resumeText && !file)}
                        className="px-6 py-3 bg-gradient-to-r from-primary-600 to-indigo-600 text-white rounded-xl font-semibold shadow-md hover:shadow-lg transition disabled:opacity-70 flex items-center justify-center gap-2"
                    >
                        {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <><FileText className="w-5 h-5" /> Generate AI Analysis</>}
                    </button>
                </form>

                {error && (
                    <div className="mt-4 p-4 bg-red-50 text-red-600 rounded-xl flex items-start gap-3">
                        <AlertCircle className="w-5 h-5 flex-shrink-0" />
                        <p>{error}</p>
                    </div>
                )}
            </div>

            {analysis && (
                <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="grid grid-cols-1 md:grid-cols-2 gap-6"
                >
                    {/* Main Score Card */}
                    <div className="md:col-span-2 glass-panel p-6 rounded-2xl flex flex-col md:flex-row items-center gap-8 justify-between bg-gradient-to-r from-white to-primary-50/50">
                        <div className="flex flex-col items-center justify-center text-center p-4 bg-white rounded-2xl shadow-sm border border-slate-100 min-w-[200px]">
                            <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-2">Overall Score</h3>
                            <div className={`text-7xl font-black tracking-tighter ${analysis.score >= 80 ? 'text-green-500' : analysis.score >= 60 ? 'text-yellow-500' : 'text-red-500'}`}>
                                {analysis.score}<span className="text-2xl text-slate-300">/100</span>
                            </div>
                        </div>

                        <div className="flex-1 space-y-4">
                            <div className="p-4 bg-white/60 rounded-xl border border-white">
                                <h4 className="font-bold text-slate-800 mb-1">Professional Summary</h4>
                                <p className="text-slate-600 text-sm leading-relaxed">{analysis.professional_summary}</p>
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div className="p-4 bg-white/60 rounded-xl border border-white flex flex-col items-center">
                                    <span className="text-xs font-bold text-slate-400 uppercase">Formatting</span>
                                    <span className="text-2xl font-bold text-slate-800">{analysis.formatting_score}%</span>
                                </div>
                                <div className="p-4 bg-white/60 rounded-xl border border-white flex flex-col items-center">
                                    <span className="text-xs font-bold text-slate-400 uppercase">Keywords</span>
                                    <span className="text-2xl font-bold text-slate-800">{analysis.keyword_score}%</span>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="glass-panel p-6 rounded-2xl space-y-6">
                        <div>
                            <h3 className="text-lg font-bold text-slate-800 mb-3 flex items-center gap-2">
                                <CheckCircle className="w-5 h-5 text-green-500" />
                                Key Strengths
                            </h3>
                            <ul className="space-y-2">
                                {analysis.key_strengths.map((str, i) => (
                                    <li key={i} className="flex items-start gap-2 text-slate-600 text-sm">
                                        <span className="shrink-0 w-1.5 h-1.5 mt-1.5 rounded-full bg-green-400"></span>
                                        {str}
                                    </li>
                                ))}
                            </ul>
                        </div>

                        <div className="pt-4 border-t border-slate-100">
                            <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-3">Extracted Skills</h3>
                            <div className="flex flex-wrap gap-2">
                                {analysis.extracted_skills.map((skill, i) => (
                                    <span key={i} className="px-3 py-1 bg-slate-100 text-slate-700 text-xs font-medium rounded-md border border-slate-200">
                                        {skill}
                                    </span>
                                ))}
                            </div>
                        </div>
                    </div>

                    <div className="glass-panel p-6 rounded-2xl space-y-6">
                        <div>
                            <h3 className="text-lg font-bold text-slate-800 mb-3 flex items-center gap-2">
                                <AlertCircle className="w-5 h-5 text-yellow-500" />
                                Missing Critical Skills
                            </h3>
                            <div className="flex flex-wrap gap-2">
                                {analysis.missing_skills.map((skill, i) => (
                                    <span key={i} className="px-3 py-1 bg-yellow-50 text-yellow-700 text-sm font-medium rounded-md border border-yellow-200">
                                        {skill}
                                    </span>
                                ))}
                            </div>
                        </div>

                        <div className="pt-4 border-t border-slate-100">
                            <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-3">Suitable Roles Based on Profile</h3>
                            <div className="flex flex-wrap gap-2">
                                {analysis.tailored_roles.map((role, i) => (
                                    <span key={i} className="px-3 py-1 bg-primary-50 text-primary-700 text-xs font-medium rounded-full border border-primary-200 shadow-sm">
                                        {role}
                                    </span>
                                ))}
                            </div>
                        </div>
                    </div>

                    <div className="md:col-span-2 glass-panel p-6 rounded-2xl border-t-4 border-t-primary-500">
                        <h3 className="text-lg font-black text-slate-800 mb-4 uppercase tracking-wide">Actionable Feedback</h3>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            {analysis.improvement_suggestions.map((suggestion, i) => (
                                <div key={i} className="flex items-start gap-4 bg-slate-50 p-4 rounded-xl border border-slate-200">
                                    <div className="w-8 h-8 rounded-full bg-primary-100 text-primary-600 flex items-center justify-center flex-shrink-0 font-black shadow-sm">{i + 1}</div>
                                    <p className="text-slate-700 text-sm font-medium leading-relaxed">{suggestion}</p>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Skills Radar Chart */}
                    <div className="md:col-span-2 glass-panel p-6 rounded-2xl mt-2 bg-slate-900 text-white">
                        <div className="flex items-center gap-3 mb-2">
                            <div className="w-8 h-8 rounded bg-gradient-to-br from-primary-400 to-indigo-500 shadow-sm flex items-center justify-center">
                                <span className="text-white text-sm font-bold">≡ƒôè</span>
                            </div>
                            <h3 className="text-2xl font-bold text-white tracking-tight">Skills Analysis</h3>
                        </div>
                        <p className="text-slate-400 text-sm mb-6 ml-11">Compare proficiency in desired role:</p>

                        <div className="h-96 w-full rounded-xl p-4">
                            <ResponsiveContainer width="100%" height="100%">
                                <RadarChart cx="50%" cy="50%" outerRadius="70%" data={[
                                    ...analysis.extracted_skills.slice(0, 3).map(skill => ({ subject: skill, current: 85, required: 95 })),
                                    ...analysis.missing_skills.slice(0, 3).map(skill => ({ subject: skill, current: 20, required: 90 })),
                                    { subject: 'Formatting', current: analysis.formatting_score, required: 100 },
                                    { subject: 'Keywords', current: analysis.keyword_score, required: 100 }
                                ]}>
                                    <PolarGrid stroke="#334155" />
                                    <PolarAngleAxis dataKey="subject" tick={{ fill: '#e2e8f0', fontSize: 13, fontWeight: 500 }} />
                                    <PolarRadiusAxis angle={30} domain={[0, 100]} tick={false} axisLine={false} />
                                    <Radar name="Current Level" dataKey="current" stroke="#0ea5e9" fill="#0ea5e9" fillOpacity={0.6} strokeWidth={2} />
                                    <Radar name="Requirement Role" dataKey="required" stroke="#6366f1" fill="#6366f1" fillOpacity={0.1} strokeWidth={2} />
                                    <Legend iconType="rect" wrapperStyle={{ paddingTop: '20px' }} />
                                    <Tooltip
                                        contentStyle={{ borderRadius: '12px', border: '1px solid #334155', backgroundColor: '#0f172a', color: '#fff', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.5)' }}
                                        itemStyle={{ fontWeight: 'bold' }}
                                    />
                                </RadarChart>
                            </ResponsiveContainer>
                        </div>
                    </div>
                </motion.div>
            )}
        </div>
    );
}

import React, { useState } from 'react';
import { Target, Search, BookOpen, AlertCircle, Loader2 } from 'lucide-react';
import { api } from '../services/api';
import { motion } from 'framer-motion';

export default function SkillGapAnalysis() {
    const [currentSkills, setCurrentSkills] = useState('');
    const [targetRole, setTargetRole] = useState('');
    const [loading, setLoading] = useState(false);
    const [analysis, setAnalysis] = useState(null);
    const [error, setError] = useState('');

    const handleAnalyze = async (e) => {
        e.preventDefault();
        if (!currentSkills.trim() || !targetRole.trim()) return;

        setLoading(true);
        setError('');
        setAnalysis(null);

        try {
            const parsedSkills = currentSkills.split(',').map(s => s.trim()).filter(s => s);
            const res = await api.post('/career/skill-gap', {
                user_skills: parsedSkills,
                target_role: targetRole
            });
            setAnalysis(res.data);
        } catch (err) {
            setError('Failed to generate skill gap analysis.');
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="space-y-6">
            <div className="glass-panel p-6 rounded-2xl">
                <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2 mb-4">
                    <Search className="w-5 h-5 text-indigo-500" />
                    Find Your Skill Gaps
                </h2>

                <form onSubmit={handleAnalyze} className="space-y-5">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2">Target Job Role</label>
                            <div className="relative">
                                <Target className="w-5 h-5 absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                                <input
                                    type="text"
                                    className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition bg-white/50"
                                    placeholder="e.g. Senior Frontend Engineer"
                                    value={targetRole}
                                    onChange={(e) => setTargetRole(e.target.value)}
                                    required
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2">Your Current Skills (comma separated)</label>
                            <input
                                type="text"
                                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition bg-white/50"
                                placeholder="React, CSS, JavaScript..."
                                value={currentSkills}
                                onChange={(e) => setCurrentSkills(e.target.value)}
                                required
                            />
                        </div>
                    </div>

                    <button
                        type="submit"
                        disabled={loading || !currentSkills || !targetRole}
