                                <li key={i} className="flex items-center gap-3 text-slate-700 text-sm bg-slate-50 p-3 rounded-lg border border-slate-100 divide-x divide-slate-200">
                                    <span className="font-bold text-slate-400 w-6">{i + 1}</span>
                                    <span className="pl-3">{priority}</span>
                                </li>
                            ))}
                        </ul>
                    </div>

                    {/* Recommended Courses */}
                    <div className="md:col-span-2 glass-panel p-6 rounded-2xl">
                        <h3 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
                            <BookOpen className="w-5 h-5 text-primary-500" />
                            Recommended Resources
                        </h3>
                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                            {analysis.recommended_courses.map((course, i) => (
                                <a
                                    key={i}
                                    href={course.url}
                                    target="_blank"
                                    rel="noopener noreferrer"
                                    className="block p-4 bg-white rounded-xl border border-slate-200 hover:border-primary-300 hover:shadow-md transition group"
                                >
                                    <h4 className="font-semibold text-slate-800 group-hover:text-primary-600 transition mb-1 line-clamp-2">{course.title}</h4>
                                    <span className="text-xs font-medium text-primary-500 uppercase tracking-wider">View Course ΓåÆ</span>
                                </a>
                            ))}
                        </div>
                    </div>

                </motion.div>
            )}
        </div>
    );
}

import React, { useState } from 'react';
import { Video, Search, ExternalLink, Loader2 } from 'lucide-react';
import { api } from '../services/api';
import { motion } from 'framer-motion';

export default function Training() {
    const [topic, setTopic] = useState('');
    const [loading, setLoading] = useState(false);
    const [trainingData, setTrainingData] = useState(null);
    const [error, setError] = useState('');

    const handleSearch = async (e) => {
        e.preventDefault();
        if (!topic.trim()) return;

        setLoading(true);
        setError('');

        try {
            const res = await api.post('/training/plan', {
                skill: topic,
                focus_area: "Fundamentals"
            });
            setTrainingData(res.data);
        } catch (err) {
            setError('Failed to fetch training modules.');
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="space-y-6">
            <div className="glass-panel p-6 rounded-2xl">
                <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2 mb-4">
                    <Video className="w-5 h-5 text-red-500" />
                    Curated Video Training
                </h2>

                <form onSubmit={handleSearch} className="flex gap-4">
                    <div className="flex-1 relative">
                        <Search className="w-5 h-5 absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <input
                            type="text"
                            className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-red-500 outline-none transition bg-white/50"
                            placeholder="Search for a skill (e.g. Next.js, Docker, Machine Learning)"
                            value={topic}
                            onChange={(e) => setTopic(e.target.value)}
                            required
                        />
                    </div>
                    <button
                        type="submit"
                        disabled={loading || !topic}
                        className="px-6 py-3 bg-slate-900 text-white rounded-xl font-semibold shadow-md hover:bg-slate-800 transition disabled:opacity-70 flex items-center gap-2"
                    >
                        {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : 'Search'}
                    </button>
                </form>
                {error && <p className="mt-4 text-red-500 text-sm">{error}</p>}
            </div>

            {trainingData && (
                <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6"
                >
                    <div className="md:col-span-2 lg:col-span-3 mb-2 mt-4 first:mt-0">
                        <h3 className="text-xl font-bold text-slate-800 border-b border-slate-200 pb-2">Training Plan for: {trainingData.skill}</h3>
                        <p className="text-slate-500 mt-2 text-sm">Estimated Timeline: {trainingData.timeline_weeks} Weeks</p>
                    </div>

                    {trainingData.videos.map((video, idx) => (
                        <a
                            key={idx}
                            href={video.url}
                            target="_blank"
                            rel="noopener noreferrer"
                            className="glass-panel rounded-2xl overflow-hidden hover:shadow-xl transition transform hover:-translate-y-1 flex flex-col group"
                        >
                            <div className="relative aspect-video w-full bg-slate-200 overflow-hidden">
                                {video.thumbnail ? (
                                    <img src={video.thumbnail} alt={video.title} className="w-full h-full object-cover group-hover:scale-105 transition duration-500" />
                                ) : (
                                    <div className="w-full h-full flex items-center justify-center bg-slate-800 text-white">
                                        <Video className="w-10 h-10 opacity-50" />
                                    </div>
                                )}
                                <div className="absolute inset-0 bg-black/10 group-hover:bg-transparent transition duration-300"></div>
                            </div>

                            <div className="p-4 flex flex-col flex-1">
                                <h4 className="font-bold text-slate-800 line-clamp-2 leading-snug mb-2 group-hover:text-red-500 transition">{video.title}</h4>
                                <p className="text-xs text-slate-500 line-clamp-2 mt-auto">Video Tutorial</p>

                                <div className="mt-4 pt-4 border-t border-slate-100 flex items-center justify-between text-sm font-medium text-slate-600">
                                    <span>YouTube</span>
                                    <ExternalLink className="w-4 h-4 group-hover:text-red-500 transition" />
                                </div>
                            </div>
                        </a>
                    ))}

                    {trainingData.videos.length === 0 && (
                        <div className="md:col-span-2 lg:col-span-3 glass-panel p-8 text-center rounded-2xl">
                            <p className="text-slate-500">No videos found for this topic using the provided key.</p>
                        </div>
                    )}
                </motion.div>
            )}
        </div>
    );
}

import React, { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { Link, useNavigate } from 'react-router-dom';
import { api, setAuthToken } from '../services/api';
import {
    BarChart3,
    FileText,
    Briefcase,
    CheckCircle,
    Video,
    LogOut,
    BookOpen,
    User,
    Menu,
    X
} from 'lucide-react';

import ResumeAnalyzer from '../components/ResumeAnalyzer';
import SkillGapAnalysis from '../components/SkillGapAnalysis';
import CareerPath from '../components/CareerPath';
import Quiz from '../components/Quiz';
import Training from '../components/Training';
import Profile from '../components/Profile';

export default function Dashboard() {
    const navigate = useNavigate();
    const [activeTab, setActiveTab] = useState('overview');
    const [progressStats, setProgressStats] = useState({ resumeScore: '--', lastQuizScore: '--' });
    const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

    useEffect(() => {
        if (activeTab === 'overview') {
            api.get('/progress/')
                .then(res => {
                    const records = res.data.records || [];
                    let resume = '--';
                    let quiz = '--';
                    records.forEach(r => {
                        if (r.module_name === 'Resume Score') resume = r.score;
                        if (r.module_name === 'Last Quiz Score') quiz = r.score;
                    });
                    setProgressStats({ resumeScore: resume, lastQuizScore: quiz });
                })
                .catch(err => console.error("Failed to load progress:", err));
        }
    }, [activeTab]);

    const handleLogout = () => {
        setAuthToken(null);
        navigate('/');
    };

    const navItems = [
        { id: 'overview', icon: BarChart3, label: 'Overview' },
        { id: 'resume', icon: FileText, label: 'Resume AI' },
        { id: 'skills', icon: Briefcase, label: 'Skill Gap' },
        { id: 'path', icon: CheckCircle, label: 'Career Path' },
        { id: 'quiz', icon: BookOpen, label: 'Quizzes & Training' },
        { id: 'profile', icon: User, label: 'Profile Settings' },
    ];

    return (
        <div className="min-h-screen bg-slate-50 flex overflow-hidden">
            {/* Mobile Sidebar Overlay */}
            {isMobileMenuOpen && (
                <div
                    className="fixed inset-0 bg-slate-900/50 z-40 md:hidden backdrop-blur-sm"
                    onClick={() => setIsMobileMenuOpen(false)}
                />
            )}

            {/* Sidebar Navigation */}
            <motion.aside
                initial={{ x: -250 }}
                animate={{ x: 0 }}
                className={`fixed md:static inset-y-0 left-0 z-50 w-64 bg-white border-r border-slate-200 flex flex-col transform transition-transform duration-300 ease-in-out ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}
            >
                <div className="h-20 flex items-center px-8 border-b border-slate-100">
                    <h2 className="text-2xl font-bold text-slate-800">
                        Vidya<span className="text-primary-600">Mitra</span>
                    </h2>
                </div>

                <nav className="flex-1 py-8 px-4 space-y-2 overflow-y-auto">
                    {navItems.map((item) => (
                        <button
                            key={item.id}
                            onClick={() => {
                                setActiveTab(item.id);
                                setIsMobileMenuOpen(false);
                            }}
                            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition ${activeTab === item.id
                                ? 'bg-primary-50 text-primary-600 font-semibold shadow-sm'
                                : 'text-slate-600 hover:bg-slate-50 hover:text-slate-900 font-medium'
                                }`}
                        >
                            <item.icon className="w-5 h-5" />
                            {item.label}
                        </button>
                    ))}
                </nav>

                <div className="p-4 border-t border-slate-200">
                    <button
                        onClick={handleLogout}
                        className="w-full flex items-center gap-3 px-4 py-3 rounded-xl text-slate-600 hover:bg-red-50 hover:text-red-600 font-medium transition"
                    >
                        <LogOut className="w-5 h-5" />
                        Sign Out
                    </button>
                </div>
            </motion.aside>

            {/* Main Content Area */}
            <main className="flex-1 overflow-y-auto w-full relative">
                <div className="absolute top-0 right-0 w-96 h-96 bg-primary-100 rounded-full blur-3xl opacity-40 -z-10 animate-pulse-slow"></div>
                <div className="p-8 pb-20">

                    {/* Header */}
                    <header className="flex justify-between items-center mb-10">
                        <div>
                            <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight">
                                {navItems.find(i => i.id === activeTab)?.label}
                            </h1>
                            <p className="text-slate-500 mt-1 placeholder">Welcome back to your career hub.</p>
                        </div>

                        <div className="flex items-center gap-4">
                            <button
                                className="md:hidden p-2 text-slate-600 hover:bg-slate-100 rounded-lg transition mr-2"
                                onClick={() => setIsMobileMenuOpen(true)}
                            >
                                <Menu className="w-6 h-6" />
                            </button>
                            {/* User Avatar / Header Actions */}
                            <button
                                onClick={() => setActiveTab('profile')}
                                className="w-10 h-10 rounded-full bg-gradient-to-tr from-primary-500 to-indigo-500 flex items-center justify-center text-white font-bold shadow-md hover:shadow-lg transition transform hover:scale-105"
                                title="My Profile"
                            >
                                U
                            </button>
                            <button
                                onClick={handleLogout}
                                className="md:hidden p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-full transition"
                                title="Sign Out"
                            >
                                <LogOut className="w-5 h-5" />
                            </button>
                        </div>
                    </header>

                    {/* Dynamic Content Mapping */}
                    <motion.div
                        key={activeTab}
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ duration: 0.3 }}
                    >
                        {activeTab === 'overview' && (
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                {/* Dynamic Stats */}
                                {['Resume Score', 'Last Quiz Score'].map((stat, i) => {
                                    const value = i === 0 ? progressStats.resumeScore : progressStats.lastQuizScore;
                                    // Resume is out of 100, Quiz is out of 5
                                    const maxScore = i === 0 ? 100 : 5;
                                    const widthPct = value !== '--' ? Math.min(100, Math.round((value / maxScore) * 100)) : 0;

                                    return (
                                        <div key={i} className="glass-panel p-6 rounded-2xl hover:shadow-2xl transition transform hover:-translate-y-1">
                                            <h3 className="text-slate-500 font-medium">{stat}</h3>
                                            <div className="text-4xl font-extrabold text-slate-800 mt-2">
                                                {value}
                                                <span className="text-xl text-slate-400 font-medium">/{maxScore}</span>
                                            </div>
                                            <div className="mt-4 h-2 w-full bg-slate-100 rounded-full overflow-hidden">
                                                <div className="h-full bg-primary-500 rounded-full transition-all duration-1000" style={{ width: `${widthPct}%` }}></div>
                                            </div>
                                        </div>
                                    );
                                })}

                                {/* Recent Activity */}
                                <div className="md:col-span-3 glass-panel p-6 rounded-2xl mt-4">
                                    <h3 className="text-xl font-bold text-slate-800 mb-4">Recent Milestones</h3>
                                    <ul className="space-y-4">
                                        <li className="flex items-center gap-4 text-slate-600 bg-white/50 p-3 rounded-xl border border-white">
                                            <CheckCircle className="w-5 h-5 text-slate-300" />
                                            No recent activity. Start by uploading your resume or taking a quiz!
                                        </li>
                                    </ul>
                                </div>
                            </div>
                        )}

                        {activeTab === 'resume' && (
                            <div className="animate-fade-in">
                                <ResumeAnalyzer />
                            </div>
                        )}

                        {activeTab === 'skills' && (
                            <div className="animate-fade-in">
                                <SkillGapAnalysis />
                            </div>
                        )}

                        {activeTab === 'path' && (
                            <div className="animate-fade-in">
                                <CareerPath />
                            </div>
                        )}

                        {activeTab === 'quiz' && (
                            <div className="animate-fade-in space-y-8">
                                <Quiz />
                                <div className="mt-8 pt-8 border-t border-slate-200">
                                    <Training />
                                </div>
                            </div>
                        )}

                        {activeTab === 'profile' && (
                            <div className="animate-fade-in">
                                <Profile />
                            </div>
                        )}

                    </motion.div>
                </div>
            </main>
        </div>
    );
}

import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { Link, useNavigate } from 'react-router-dom';
import { api, setAuthToken } from '../services/api';
import { Mail, Lock, ArrowRight, Loader2 } from 'lucide-react';

export default function Login() {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const navigate = useNavigate();

    const handleLogin = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError('');

        try {
            const res = await api.post('/auth/login', { email, password });
            setAuthToken(res.data.access_token);
            // Try to load any existing profile
            let storedProfileStr = localStorage.getItem('vidyamitra_user_profile');
            let storedProfile = storedProfileStr ? JSON.parse(storedProfileStr) : null;

            // Check if there is an existing seeded profile, if not, create a baseline
            if (!storedProfile) {
                storedProfile = {
                    name: 'VidyaMitra User',
                    role: 'Job Seeker',
                    phone: 'Add your phone number',
                    location: 'Add your location'
                };
            }

            // Force the email to match the login credentials as source of truth
            storedProfile.email = email;
            localStorage.setItem('vidyamitra_user_profile', JSON.stringify(storedProfile));
            navigate('/dashboard');
        } catch (err) {
            setError(err.response?.data?.detail || 'Failed to login');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center pt-16 px-4 relative">
            <div className="absolute top-1/4 left-1/4 w-72 h-72 bg-primary-300 rounded-full blur-3xl opacity-30 animate-pulse-slow"></div>

            <motion.div
                initial={{ y: 20, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                className="glass-panel w-full max-w-md p-8 rounded-2xl relative z-10"
            >
                <div className="text-center mb-8">
                    <h2 className="text-3xl font-extrabold text-slate-900 mb-2">Welcome Back</h2>
                    <p className="text-slate-500">Log in to continue your career journey</p>
                </div>

                {error && (
                    <div className="bg-red-50 text-red-600 p-3 rounded-lg text-sm mb-6 text-center shadow-inner">
                        {error}
                    </div>
                )}

                <form onSubmit={handleLogin} className="space-y-6">
                    <div className="space-y-1">
                        <label className="text-sm font-medium text-slate-700 ml-1">Email Address</label>
                        <div className="relative">
                            <Mail className="w-5 h-5 absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                            <input
                                type="email"
                                required
                                className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none transition bg-white/50"
                                placeholder="you@example.com"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                            />
                        </div>
                    </div>

                    <div className="space-y-1">
                        <label className="text-sm font-medium text-slate-700 ml-1">Password</label>
                        <div className="relative">
                            <Lock className="w-5 h-5 absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                            <input
                                type="password"
                                required
                                className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none transition bg-white/50"
                                placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                            />
                        </div>
                    </div>

                    <button
                        type="submit"
                        disabled={loading}
                        className="w-full flex items-center justify-center gap-2 bg-gradient-to-r from-primary-600 to-primary-500 text-white py-3 rounded-xl font-semibold shadow-lg hover:shadow-xl transition transform hover:-translate-y-0.5 disabled:opacity-70 disabled:transform-none"
                    >
                        {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : (
                            <>
                                Sign In <ArrowRight className="w-5 h-5" />
                            </>
                        )}
                    </button>
                </form>

                <p className="mt-6 text-center text-sm text-slate-600">
                    Don't have an account? <Link to="/register" className="text-primary-600 hover:text-primary-700 font-semibold transition">Register here</Link>
                </p>
            </motion.div>
        </div>
    );
}

import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { Link, useNavigate } from 'react-router-dom';
import { api, setAuthToken } from '../services/api';
import { Mail, Lock, User, ArrowRight, Loader2 } from 'lucide-react';

export default function Register() {
    const [name, setName] = useState('');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const navigate = useNavigate();

    const handleRegister = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError('');

        try {
            const res = await api.post('/auth/register', { email, password, name });
            // Seed the profile so the user sees their own info immediately when they do log in
            const defaultProfile = {
                name: name || 'VidyaMitra User',
                email: email,
                role: 'Job Seeker',
                phone: 'Add your phone number',
                location: 'Add your location'
            };
            localStorage.setItem('vidyamitra_user_profile', JSON.stringify(defaultProfile));
            navigate('/login', { state: { message: "Registration successful. Please log in." } });
        } catch (err) {
            setError(err.response?.data?.detail || 'Failed to register');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center pt-16 px-4 relative">
            <div className="absolute top-1/2 right-1/4 w-80 h-80 bg-indigo-300 rounded-full blur-3xl opacity-30 animate-pulse-slow"></div>

            <motion.div
                initial={{ scale: 0.95, opacity: 0 }}
                animate={{ scale: 1, opacity: 1 }}
                className="glass-panel w-full max-w-md p-8 rounded-3xl relative z-10"
            >
                <div className="text-center mb-8">
                    <h2 className="text-3xl font-extrabold text-slate-900 mb-2">Create Account</h2>
                    <p className="text-slate-500">Unlock your AI-powered career potential</p>
